instruction:
Without try/catch, an error stops your program dead. With it, you handle the problem and keep going.

```js
try {
  // risky code
} catch (error) {
  // runs only if an error was thrown
}
```

Run this. The crash is caught and the program continues.

starter:
console.log("Before the risky code.");

try {
  const parsed = JSON.parse("{ this is not valid JSON }");
  console.log(parsed);
} catch (error) {
  console.log("Caught:", error.message);
}

console.log("Program continues after the catch.");

try {
  null.property;  // TypeError тАФ can't access property of null
} catch (error) {
  console.log(error.name);
  console.log(error.message);
  // error.stack is too long тАФ just check the first line
  console.log(error instanceof TypeError);
  console.log(error instanceof Error);
}

const errors = [
  () => null.property,
  () => undeclaredVariable,
  () => new Array(-1),
];

errors.forEach(fn => {
  try {
    fn();
  } catch (e) {
    console.log(`${e.name}: ${e.message}`);
  }
});

function withdraw(balance, amount) {
  if (typeof amount !== 'number') {
    throw new TypeError(`Amount must be a number, got ${typeof amount}`);
  }
  if (amount < 0) {
    throw new RangeError(`Amount must be positive, got ${amount}`);
  }
  if (amount > balance) {
    throw new Error(`Insufficient funds: need ${amount}, have ${balance}`);
  }
  return balance - amount;
}

const tests = [
  () => withdraw(100, 50),
  () => withdraw(100, "50"),
  () => withdraw(100, -10),
  () => withdraw(100, 200),
];

tests.forEach(fn => {
  try {
    console.log("Result:", fn());
  } catch(e) {
    console.log(`${e.name}: ${e.message}`);
  }
});

class AppError extends Error {
  constructor(message, code) {
    super(message);
    this.name = "AppError";
    this.code = code;
  }
}

// TODO: add ValidationError(field, message) тАФ extends AppError, sets field
class ValidationError extends AppError {
  constructor(field, message) {
    super(message, "VALIDATION_ERROR");
    this.name = "ValidationError";
    this.field = field;
  }
}

try {
  throw new ValidationError("email", "Invalid email format");
} catch (e) {
  console.log(e.name);
  console.log(e.message);
  console.log(e.field);
  console.log(e instanceof ValidationError);
  console.log(e instanceof AppError);
  console.log(e instanceof Error);
}

instruction:
`finally` runs whether or not an error occurred тАФ perfect for cleanup:

```js
try {
  // open file / DB connection
} catch (e) {
  // handle error
} finally {
  // ALWAYS close / clean up
}
```

Simulate a database query with guaranteed cleanup.

starter:
function queryDatabase(query) {
  console.log("Opening connection...");
  try {
    if (!query) throw new Error("Query cannot be empty");
    console.log(`Running: ${query}`);
    return { rows: 5 };
  } catch (e) {
    console.log(`Query failed: ${e.message}`);
    return null;
  } finally {
    console.log("Closing connection.");  // always runs!
  }
}

queryDatabase("SELECT * FROM users");
console.log("---");
queryDatabase("");

instruction:
A catch block should only handle errors it understands. Re-throw anything else:

```js
catch (e) {
  if (e instanceof ValidationError) {
    // handle it
  } else {
    throw e;  // re-throw тАФ not our problem
  }
}
```

Fix the overly broad catch that swallows everything.

starter:
class ValidationError extends Error {
  constructor(msg) { super(msg); this.name = "ValidationError"; }
}

function processForm(data) {
  try {
    if (!data.email) throw new ValidationError("Email required");
    if (!data.name)  undefinedFunction(); // simulates an unexpected bug
    return "Success";
  } catch (e) {
    // BUG: this catches ALL errors, even unexpected ones!
    // TODO: only handle ValidationError, re-throw others
    return "Validation failed: " + e.message;
  }
}

try {
  processForm({ email: "", name: "Alex" });
} catch(e) { console.log("Caught outer:", e.message); }

try {
  processForm({ name: "" });
} catch(e) { console.log("Caught outer:", e.message); }
